import React from 'react';
import { FileText, ArrowRight } from 'lucide-react';
import Card from './Card';

const PleadingCard = ({ title, description, date, status }) => (
  <Card className="p-6 hover:bg-slate-50 dark:hover:bg-slate-800 transition-colors">
    <div className="flex items-start justify-between">
      <div className="flex items-start space-x-4">
        <div className="p-2 bg-blue-100 dark:bg-blue-900 rounded-lg">
          <FileText className="h-6 w-6 text-blue-600 dark:text-blue-400" />
        </div>
        <div>
          <h3 className="text-lg font-semibold text-gray-900 dark:text-white">{title}</h3>
          <p className="mt-1 text-sm text-gray-500 dark:text-gray-400">{description}</p>
          <p className="mt-2 text-sm text-gray-500 dark:text-gray-400">{date}</p>
        </div>
      </div>
      <span className={`px-3 py-1 rounded-full text-sm font-medium ${
        status === 'New' ? 'bg-green-100 text-green-800 dark:bg-green-900 dark:text-green-200' :
        status === 'Updated' ? 'bg-blue-100 text-blue-800 dark:bg-blue-900 dark:text-blue-200' :
        'bg-gray-100 text-gray-800 dark:bg-gray-700 dark:text-gray-200'
      }`}>
        {status}
      </span>
    </div>
    <div className="mt-4 flex items-center text-sm text-blue-600 dark:text-blue-400 hover:underline cursor-pointer">
      View details
      <ArrowRight className="ml-2 h-4 w-4" />
    </div>
  </Card>
);

const PleadingsPage = () => {
  const pleadings = [
    {
      title: "Complaint Filing Guidelines",
      description: "Complete guide for filing initial complaints in civil cases",
      date: "Updated: January 2024",
      status: "Updated"
    },
    {
      title: "Answer to Complaint Template",
      description: "Standard format for responding to civil complaints",
      date: "Added: December 2023",
      status: "New"
    },
    {
      title: "Motion Response Templates",
      description: "Collection of templates for responding to common motions",
      date: "Added: December 2023",
      status: "Standard"
    }
  ];

  return (
    <div className="space-y-8">
      <div>
        <h1 className="text-3xl font-bold text-gray-900 dark:text-white mb-4">
          Pleadings
        </h1>
        <p className="text-gray-600 dark:text-gray-400 max-w-3xl">
          Access comprehensive information about legal pleadings, including templates, 
          guidelines, and best practices for various types of legal documents.
        </p>
      </div>

      <div className="grid gap-6">
        {pleadings.map((pleading, index) => (
          <PleadingCard key={index} {...pleading} />
        ))}
      </div>
    </div>
  );
};

export default PleadingsPage;
